INSERT OR REPLACE INTO mid_chains (chain, launched, tvl, verdict, why_stuck, outlook, profile, sources, updated_at) VALUES ('Tezos', '2018-06', 21143989, 'pivoting', 'Tezos spent seven years as a self-contained, self-amending L1 with its own Michelson language and on-chain governance, and almost none of it produced durable DeFi or users — so the team has effectively conceded that thesis and bet the franchise on Etherlink, an EVM L2, quietly retiring the original chain''s value proposition rather than fixing it.', 'BULL: Tezos X unifies Michelson and EVM on one ledger and Etherlink''s 2025 TVL surge (roughly $1.5M to ~$82M) compounds, giving XTZ a real EVM-L2 story and settlement-layer value capture. BASE (most likely): Etherlink keeps growing off incentives (a $3M ''Apple Farm'' program) but stays a mid-tier L2 among dozens, while the legacy L1 keeps bleeding relevance and XTZ trades as sector beta, not on fundamentals. BEAR: Etherlink''s TVL proves incentive-dependent and unwinds, Tezos X ships late or underwhelms, and Tezos remains a well-funded ghost chain with a strong treasury but no narrative. Top risks: incentive-driven TVL that doesn''t stick, L2 commoditization, and no mechanism tying Etherlink usage to XTZ value. Watch: Tezos X mainnet activation, Etherlink TVL retention after incentives taper, and whether any Etherlink app reaches organic escape velocity.', '{"founded": "2018-06", "founders": "Arthur Breitman (ex-Goldman/Morgan Stanley quant, wrote the original code) and Kathleen Breitman (ex-Bridgewater, Accenture, R3) — a husband-and-wife team who first proposed Tezos in 2014.", "raised": "Raised $232M in BTC/ETH in a July 2017 ICO, one of the largest of its era, via the Zug-based Tezos Foundation. A founder-vs-foundation governance fight delayed launch and triggered class-action suits alleging an unregistered securities sale; the Foundation settled for $25M in 2020 and remains a large, well-capitalized ecosystem funder.", "token_symbol": "XTZ", "token_ath": 9.12, "token_ath_date": "2021-10", "token_current": 0.221749, "purpose": "A self-amending proof-of-stake L1 built around formal-verification-friendly smart contracts (Michelson / liquid PoS) and on-chain governance that upgrades itself without hard forks. Its current thesis has shifted to being the settlement layer for Etherlink, its EVM-compatible L2.", "situation": "Tezos has effectively pivoted its whole narrative from the native Michelson L1 to Etherlink, an EVM L2 launched in 2024. Through 2025 Etherlink shipped rapid upgrades (fast withdrawals cut from ~15 days to under a minute, higher throughput) and its TVL grew from roughly $1.5M to ~$82M, aided by DeFi integrations (Morpho, Curve) and a $3M ''Apple Farm'' incentive program. The next step, Tezos X, aims to unify Michelson and EVM on a single shared ledger with atomic cross-interface calls. Meanwhile the native L1''s own DeFi TVL sits at only ~$21M and XTZ trades ~98% below its 2021 ATH. Developer activity is a bright spot: ~229 monthly active contributors across 4,300+ repos in Q4 2025.", "whats_working": "A deep, disciplined engineering culture with a rare cadence of self-amending upgrades; a large, well-funded Foundation treasury for grants and incentives; genuine 2025 momentum on Etherlink (TVL up 50x+, real DeFi protocol integrations, fast withdrawals); and rising developer contributor counts. Tezos X is a technically ambitious attempt at a unified Michelson+EVM ledger.", "whats_not": "The original L1 thesis — bespoke language, formal verification, on-chain governance — never produced a killer app or meaningful DeFi, so the team is effectively conceding it by going EVM. Etherlink''s TVL is still small in absolute terms and leans on incentives, competing against dozens of established L2s with no obvious edge. There is no clear mechanism linking Etherlink activity to XTZ value, and years of upgrades haven''t moved price or mindshare off multi-year lows.", "non_economic": "Media framing has flipped from ''over-engineered, litigation-scarred, no traction'' to a cautiously positive ''the EVM pivot is working'' story around Etherlink''s TVL growth. Dev activity is a real positive signal (contributor counts up QoQ). But retail and speculator mindshare stay low — Tezos is widely treated as a legacy 2021-era name, and the Breitmans no longer carry the founder mystique they once did.", "outlook": "BULL: Tezos X unifies Michelson and EVM on one ledger and Etherlink''s 2025 TVL surge (roughly $1.5M to ~$82M) compounds, giving XTZ a real EVM-L2 story and settlement-layer value capture. BASE (most likely): Etherlink keeps growing off incentives but stays a mid-tier L2 among dozens, while the legacy L1 keeps bleeding relevance and XTZ trades as sector beta. BEAR: Etherlink''s TVL proves incentive-dependent and unwinds, Tezos X ships late, and Tezos remains a well-funded ghost chain with no narrative. Top risks: incentive-driven TVL that doesn''t stick, L2 commoditization, no value link to XTZ. Watch: Tezos X mainnet activation, Etherlink TVL retention after incentives taper, organic app traction.", "success_factors_missing": ["no_killer_app", "lost_narrative", "no_value_capture", "unclear_positioning", "faded_hype"]}', '[{"title": "State of Tezos Q4 2025 — Messari", "url": "https://messari.io/report/state-of-tezos-q4-2025"}, {"title": "Tezos X: From Roadmap to Reality — Tezos Spotlight", "url": "https://spotlight.tezos.com/tezos-x-from-roadmap-to-reality/"}, {"title": "Etherlink Caps Transformative 2025 — Tezos", "url": "https://tezos.com/media-center/2025/etherlink-2025/"}, {"title": "Tezos — Wikipedia (history, ICO, founders)", "url": "https://en.wikipedia.org/wiki/Tezos"}, {"title": "Backroom battle imperils $230M cryptocurrency venture — CNBC", "url": "https://www.cnbc.com/2017/10/19/backroom-battle-imperils-230-million-cryptocurrency-venture.html"}]', datetime('now'));
INSERT OR REPLACE INTO mid_chains (chain, launched, tvl, verdict, why_stuck, outlook, profile, sources, updated_at) VALUES ('Flow', '2020-10', 11293535, 'drifting', 'Flow was purpose-built to scale mainstream consumer collectibles and delivered exactly one breakout — NBA Top Shot — before the 2021 NFT wave broke, and since then it has hopped between NFL All Day, Disney Pinnacle, Cadence 1.0, Flow EVM and now ''consumer DeFi'' without a second flagship, so a chain with 40M+ accounts still has almost no on-chain economic value and a token down ~99.9% from its peak.', 'BULL: Flow''s Forte upgrade (onchain automation) plus Flow EVM converts its 40M+ consumer accounts and blue-chip IP (NBA, NFL, Disney, Ticketmaster) into real consumer-DeFi usage, and moving Top Shot fully onchain revives collectible demand. BASE (most likely): Flow keeps shipping and retains its consumer footprint, but activity stays collectibles-driven and low-value, EVM adoption is modest, and FLOW trades as a low-cap legacy name. BEAR: the consumer-DeFi pivot fails to find product-market fit, Dapper''s IP relationships monetize off-chain instead, and confidence erodes further after the reported late-2025 exploit-and-rollback and the 2026 pause of NFL NFT minting. Top risks: no killer app since Top Shot, centralization perception after the rollback, IP-partner and regulatory dependence (the Top Shot securities suit), and weak token value capture. Watch: whether any Flow EVM/consumer-DeFi app gains organic traction, the Top Shot onchain migration, and what Dapper''s paused ''next-generation product'' turns out to be.', '{"founded": "2020-10", "founders": "Built by Dapper Labs — CEO Roham Gharegozlou, CTO Dieter Shirley (lead author of the ERC-721 NFT standard), and co-founder Mikhael Naayem. Dapper''s earlier hit CryptoKitties (2017) congested Ethereum and directly motivated building Flow as a purpose-built consumer chain.", "raised": "Dapper Labs raised roughly $666M across ~9 rounds: a $12.3M seed in 2018 led by a16z and Union Square Ventures, and a $250M round in September 2021 led by Coatue with a16z, GV, BOND and GIC, peaking at a ~$7.6B valuation. The FLOW token had a 2020 community/CoinList sale.", "token_symbol": "FLOW", "token_ath": 42.4, "token_ath_date": "2021-04", "token_current": 0.02607083, "purpose": "A layer-1 designed for mainstream consumer apps and NFTs, using a multi-role pipelined architecture and the resource-oriented Cadence language to scale collectibles and games without sharding. It is now repositioning toward ''consumer DeFi'' via Flow EVM equivalence and onchain automation.", "situation": "Flow is mid-repositioning from a pure NFT/collectibles chain to what Messari frames as ''consumer DeFi.'' The September 2024 Crescendo upgrade shipped EVM equivalence (Flow EVM) and Cadence 1.0, and the October 2025 Forte upgrade added composable onchain operations for automation. Its consumer footprint is large on paper — 40M+ unique accounts and ~950M cumulative transactions across NBA Top Shot, NFL All Day, Disney Pinnacle and Ticketmaster — but on-chain TVL is only ~$11M and FLOW trades ~99.9% below its 2021 ATH. Per Messari, the network suffered a ~$3.9M exploit in late 2025 that required a coordinated rollback, and Dapper paused NFL NFT minting in 2026 to focus on a ''next-generation product.'' Top Shot is being migrated to a fully onchain architecture.", "whats_working": "Unmatched blue-chip consumer IP for a blockchain (NBA, NFL, Disney, Ticketmaster) and a genuinely large user base (40M+ accounts, ~950M txns) — reach most L1s can only envy. Strong technical pedigree (Dieter Shirley/ERC-721), a maturing stack (Cadence 1.0, Flow EVM equivalence, Forte automation), and a deep-pocketed backer set. The Top Shot fully-onchain migration is a credible attempt to make the flagship matter again.", "whats_not": "One breakout (Top Shot) and no encore — the huge account base is a legacy of the 2021 NFT bubble and generates almost no current economic value (~$11M TVL). The chain keeps changing thesis (collectibles → games → EVM → consumer DeFi) without a new flagship, Cadence''s non-EVM design historically fragmented developer mindshare, and the reported late-2025 exploit-and-rollback undercut decentralization credibility. FLOW has essentially no value capture and sits near all-time lows.", "non_economic": "Media framing has cooled from 2021 ''home of NBA Top Shot'' euphoria to a skeptical ''what is Flow for now?'', with the consumer-DeFi pivot drawing measured, not enthusiastic, coverage. The reported rollback drew centralization criticism, and pausing NFL minting reads as strategic churn. Community energy is a fraction of its peak; Flow now leans on partnership announcements more than organic grassroots momentum, with overhang from the Top Shot securities lawsuit.", "outlook": "BULL: Forte automation plus Flow EVM converts 40M+ accounts and blue-chip IP into real consumer-DeFi usage, and moving Top Shot fully onchain revives demand. BASE (most likely): Flow keeps its consumer footprint but activity stays collectibles-driven and low-value, EVM adoption modest, FLOW a low-cap legacy name. BEAR: the pivot fails PMF, IP monetizes off-chain, and confidence erodes after the rollback and the NFL-minting pause. Top risks: no killer app since Top Shot, centralization perception, IP/regulatory dependence, weak value capture. Watch: any organic Flow EVM traction, the Top Shot migration, and Dapper''s paused ''next-generation product.''", "success_factors_missing": ["no_killer_app", "lost_narrative", "no_value_capture", "faded_hype", "unclear_positioning"]}', '[{"title": "State of Flow Q1 2026 — Messari", "url": "https://messari.io/report/state-of-flow-q1-2026"}, {"title": "Flow Network: From Collectibles to Consumer DeFi — Messari", "url": "https://messari.io/report/flow-network-from-collectibles-to-consumer-defi"}, {"title": "How NBA Top Shot Is Moving Fully Onchain — Flow", "url": "https://flow.com/post/how-nba-top-shot-is-moving-its-footage-and-artwork-fully-onchain"}, {"title": "Dapper Labs Announces $250M from Coatue, a16z, GV, BOND, GIC", "url": "https://www.dapperlabs.com/newsroom/dapper-labs-announces-250m-in-funding-from-coatue-a16z-gv-bond-gic-and-more"}, {"title": "NBA Top Shot creator to face securities-status lawsuit — TechCrunch", "url": "https://techcrunch.com/2023/02/23/nba-top-shot-creator-to-face-lawsuit-around-securities-status/"}, {"title": "Dapper Labs valued at $7.6B in latest round — Sportico", "url": "https://www.sportico.com/business/tech/2021/dapper-labs-valuation-7-billion-top-shot-1234640429/"}]', datetime('now'));
INSERT OR REPLACE INTO mid_chains (chain, launched, tvl, verdict, why_stuck, outlook, profile, sources, updated_at) VALUES ('Hedera', '2019-09', 24517491, 'stalling', 'Hedera has assembled a blue-chip enterprise Council and a credible RWA/tokenization narrative, but seven years in that story still hasn''t converted into on-chain economic activity or token demand — DeFi TVL sits near $24.5M and HBAR trades ~88% below its 2021 peak. It is stuck in permanent ''enterprise pilot'' purgatory: real logos, real tech, negligible value capture.', 'BULL: Institutional RWA/tokenization actually lands at scale (native stablecoins, tokenized treasuries/securities), a fixed-fee ''real yield'' narrative pulls capital, and Council credibility becomes a moat as regulated tokenization goes mainstream. BASE (most likely): keeps shipping enterprise partnerships and carbon/identity pilots that generate headlines but little TVL or token demand; HBAR trades as a beta on ''tokenization'' sentiment rather than on Hedera-specific usage. BEAR: EVM L2s and Council-member alternatives capture the tokenization demand Hedera has evangelized, leaving a well-governed network no one settles value on. Top risks: value never accrues to HBAR despite usage; governance-by-committee slows shipping; dependence on a few flagship deals. Watch: DeFi/stablecoin TVL trend, whether tokenized-RWA notional translates to fee revenue, EVM developer migration, and any Council attrition.', '{"founded": "2019-09", "founders": "Dr. Leemon Baird (inventor of the hashgraph aBFT consensus algorithm) and Mance Harmon, via their company Swirlds; the Hedera entity formed in 2017, was publicly unveiled in March 2018, and reached open-access mainnet in September 2019.", "raised": "Raised ~$124M across pre-sale/SAFT rounds (2018) plus later treasury sales; the real ''raise'' is governance — a Hedera Governing Council of up to 39 term-limited global enterprises (members have included Google, IBM, Boeing, Deutsche Telekom, LG, Tata Communications, FIS/Worldpay, Standard Bank), each running a node and guaranteeing the network will not fork.", "token_symbol": "HBAR", "token_ath": 0.569229, "token_ath_date": "2021-09", "token_current": 0.066341, "purpose": "A public, enterprise-grade DLT using aBFT hashgraph consensus for high throughput, 3–5s finality and fixed USD-pegged fees, positioned for regulated real-world-asset tokenization, stablecoins, carbon markets, verifiable identity/compute and enterprise settlement rather than retail DeFi.", "situation": "Through 2025-2026 Hedera leaned hard into the RWA/tokenization thesis: native and third-party stablecoins via Stablecoin Studio, USDC expansion, and partners tokenizing commercial real estate, diamonds and money-market/securities pilots. It also pushed carbon markets (Guardian) and verifiable-compute/identity angles, and made HTS and the Smart Contract Service fully EVM-compatible to ease Ethereum-app portability. Yet none of this has meaningfully lifted DeFi TVL (~$24.5M) or HBAR, which remains ~88% below its 2021 ATH.", "whats_working": "Genuinely differentiated, patented aBFT tech with predictable low fees and fast finality; unmatched enterprise governance credibility (household-name Council); a coherent, regulation-friendly tokenization/carbon/identity narrative; a growing set of real tokenization and stablecoin deployments; and energy-efficient ''green'' positioning that appeals to compliance-conscious institutions.", "whats_not": "Almost no value accrues to HBAR from all the enterprise activity; the DeFi/liquidity ecosystem is tiny and concentrated (a couple of DEXs); developer mindshare is dwarfed by EVM L2s; the ''enterprise adoption'' story has been perpetually one deal away for years; token/treasury overhang and slow committee governance weigh on it; and the brand still reads as ''permissioned-ish'' to crypto-native builders.", "non_economic": "A steady drumbeat of Council announcements, RWA partnerships and pilots keeps Hedera in enterprise/tokenization headlines; a loyal but relatively insular retail community (the HBAR ''army''); active participation in carbon-market and identity standards bodies; and developer activity that exists but is modest versus EVM ecosystems and skews toward enterprise integrators rather than open DeFi builders.", "outlook": "BULL: Institutional RWA/tokenization lands at scale, a fixed-fee ''real yield'' narrative pulls capital, and Council credibility becomes a moat. BASE (most likely): keeps shipping enterprise partnerships and pilots that generate headlines but little TVL or token demand; HBAR trades as a beta on tokenization sentiment. BEAR: EVM L2s and rival chains capture the tokenization demand Hedera evangelized. Top risks: no value accrual to HBAR, committee-paced shipping, over-reliance on a few flagship deals. Watch: DeFi/stablecoin TVL, RWA notional-to-fee conversion, EVM developer migration, Council attrition.", "success_factors_missing": ["value_capturing_token", "defi_liquidity_depth", "developer_mindshare", "retail_killer_app", "narrative_momentum"]}', '[{"title": "DefiLlama — Hedera chain TVL", "url": "https://defillama.com/chain/Hedera"}, {"title": "Hedera — Journey / history & founders", "url": "https://hedera.com/journey/"}, {"title": "Hedera (distributed ledger) — Wikipedia", "url": "https://en.wikipedia.org/wiki/Hedera_(distributed_ledger)"}, {"title": "Hedera Council — FAQ (governance model)", "url": "https://hederacouncil.org/faq"}, {"title": "Tokeny & HBAR Foundation — institutional tokenization partnership", "url": "https://tokeny.com/tokeny-and-hbar-foundation-partner-to-deliver-compliant-scalable-and-green-institutional-tokenization-on-the-hedera-network/"}, {"title": "CoinGecko — HBAR price & ATH", "url": "https://www.coingecko.com/en/coins/hedera"}]', datetime('now'));
INSERT OR REPLACE INTO mid_chains (chain, launched, tvl, verdict, why_stuck, outlook, profile, sources, updated_at) VALUES ('MultiversX', '2020-07', 9908089, 'pivoting', 'MultiversX has strong sharded-WASM tech but a chronic identity problem: it has chased the story of every cycle — high-performance L1, then a metaverse/super-app, now an AI narrative — without any becoming a durable, value-capturing killer app. TVL near $10M and EGLD ~99% below its ATH show the market no longer prices the pivots.', 'BULL: one of MultiversX''s pivots finally sticks — the sharded/WASM stack plus xPortal''s consumer distribution produce a genuine flagship (payments, gaming, or an AI/agentic use-case) that drives real, non-incentivized on-chain volume. BASE (most likely): keeps shipping credible tech and chasing the current cycle''s narrative with a committed core community but thin liquidity and mindshare; EGLD trades on hype cycles, not usage. BEAR: serial-pivot fatigue erodes credibility, the ecosystem shrinks into a well-engineered chain almost no one builds on, and EGLD stays near lows. Top risks: narrative whiplash undermining trust; a founder- and EU-centric ecosystem; tiny DeFi liquidity; no clear value capture to EGLD. Watch: whether any pivot produces retained users and organic on-chain volume, xPortal active users, and the DeFi TVL trend.', '{"founded": "2020-07", "founders": "Beniamin Mincu (CEO), with co-founders Lucian Mincu (CIO) and Lucian Todea (COO); the project began as Elrond, sold its ERD token on Binance Launchpad in July 2019, and launched mainnet in 2020 (ERD later redenominated to EGLD, ''eGold'').", "raised": "Raised ~$1.9M in a 2019 private round (backers included Binance Labs and Electric Capital) and ~$3.25M in the July 2019 Binance Launchpad IEO, plus later ecosystem raises. Governed by the MultiversX Foundation with Beniamin Mincu as the central, highly visible leader.", "token_symbol": "EGLD", "token_ath": 545.64, "token_ath_date": "2021-11", "token_current": 3.08, "purpose": "A high-throughput L1 using adaptive state sharding and a WASM-based virtual machine for fast, cheap smart contracts, originally pitched as an ''internet-scale'' blockchain and later repositioned around a consumer super-app (xPortal) and, more recently, AI/agentic narratives.", "situation": "After rebranding from Elrond in November 2022, MultiversX rotated its identity from a high-throughput sharded L1 into a consumer ''super-app'' thesis around xPortal (wallet, payments, staking), and has more recently reoriented its messaging toward AI and agentic use-cases. The pattern is the problem: each narrative tends to arrive before the previous one matures into a durable, value-capturing product. The self-built stack (adaptive state sharding, a WASM VM) is technically credible, but on-chain economics have stayed thin — DeFi TVL sits near $9.9M and EGLD trades near $3 against a $545 ATH, roughly 99% down.", "whats_working": "A solid, self-built technical stack (adaptive state sharding, WASM VM); a genuine consumer product in xPortal (wallet, payments, card, staking) that most L1s lack; a habit of moving onto emerging narratives early; a dedicated core community; an unusually visible, communicative founder; and developer tooling plus gaming/onboarding initiatives.", "whats_not": "No durable killer app — each pivot (L1 → super-app → AI) resets the narrative before the prior one matures; very thin DeFi liquidity and TVL; EGLD''s ~99% drawdown signals lost investor confidence; heavy dependence on the founder''s brand; and an ecosystem concentrated in Europe with limited global developer mindshare.", "non_economic": "A high founder social-media presence (Beniamin Mincu is a prominent EU crypto voice) drives most of the attention; an active launchpad and NFT marketplace and gaming initiatives exist; the community is loyal but relatively small; and product/tooling releases ship steadily, but engagement and dev activity stay modest relative to the ambition of the messaging.", "outlook": "BULL: a pivot finally sticks and xPortal distribution gives it a real flagship driving organic volume. BASE (most likely): keeps shipping credible tech and chasing the current narrative with a committed core community but thin liquidity; EGLD trades on hype, not usage. BEAR: serial-pivot fatigue erodes trust and the ecosystem shrinks. Top risks: narrative whiplash, founder/EU concentration, tiny liquidity, no value capture. Watch: retained users and organic volume from any pivot, xPortal actives, and DeFi TVL.", "success_factors_missing": ["durable_killer_app", "narrative_consistency", "defi_liquidity_depth", "value_capturing_token", "global_developer_mindshare"]}', '[{"title": "DefiLlama — MultiversX chain TVL", "url": "https://defillama.com/chain/MultiversX"}, {"title": "MultiversX — Transformation (Elrond → MultiversX rebrand)", "url": "https://multiversx.com/transformation"}, {"title": "Coin Bureau — Elrond to MultiversX analysis (history & funding)", "url": "https://coinbureau.com/review/elrond-erd"}, {"title": "Messari — MultiversX Foundation project profile", "url": "https://messari.io/project/multivers-x-foundation"}, {"title": "Binance Research — MultiversX (EGLD)", "url": "https://www.binance.com/en/research/projects/multiversx"}, {"title": "CoinGecko — EGLD price & ATH", "url": "https://www.coingecko.com/en/coins/elrond"}]', datetime('now'));
INSERT OR REPLACE INTO mid_chains (chain, launched, tvl, verdict, why_stuck, outlook, profile, sources, updated_at) VALUES ('Kaia', '2024-08', 10677764, 'pivoting', 'Kaia is a defensive merger of two national-champion chains (Kakao''s Klaytn and LINE''s Finschia) that never found DeFi traction independently, and is now betting its entire relevance on funneling LINE/KakaoTalk''s hundreds of millions of messenger users into mini-dApps and Asian stablecoin payments. The distribution is real but the on-chain economy is tiny (~$10.7M TVL) and the token has collapsed, so the pivot is unproven where it counts.', 'BULL: the LINE/KakaoTalk messenger distribution moat (a stablecoin super-app, native USDT, KRW/JPY rails) converts a fraction of 200M+ users into recurring on-chain payment/RWA activity, giving Kaia a genuine consumer-fintech niche no US L2 can copy. BASE (most likely): mini-dApp user counts stay headline-friendly but shallow — high signups, low retention, near-zero TVL growth — while Kaia consolidates as a regional payments/stablecoin settlement layer rather than a DeFi hub. BEAR: mini-dApp novelty fades, stablecoin regulation in Korea/Japan stalls the flagship thesis, and KAIA keeps grinding to lows as sell pressure meets weak fundamentals. Top risks: token depreciation eroding incentive budgets; regulatory dependence (KR/JP stablecoin law); reliance on two corporate parents'' willingness to keep pushing crypto in-app. Watch: whether the stablecoin super-app ships and shows retained paying users; TVL/stablecoin supply on Kaia; KAIA versus its ~$0.05 low.', '{"founded": "2024-08", "founders": "Kaia DLT Foundation (Singapore), formed by merging Kakao''s Klaytn (launched June 2019, South Korea) and LINE''s Finschia (formerly LINK) on 29 Aug 2024. Backed by the two dominant East Asian messenger operators — Kakao (KakaoTalk) and LY Corp / LINE NEXT (LINE).", "raised": "No single headline VC round; capitalized via the corporate treasuries and prior token ecosystems of Klaytn (Kakao''s Ground X / Klaytn Foundation) and Finschia (LINE). Ecosystem funding now flows through the Kaia Wave program and grants rather than external fundraises.", "token_symbol": "KAIA", "token_ath": 0.406698, "token_ath_date": "2024-12", "token_current": 0.03360552, "purpose": "An EVM-compatible Layer-1 optimized for consumer ''mini-dApps'' embedded directly inside the LINE and KakaoTalk messengers, plus Asian stablecoin settlement, payments/remittances, RWAs and gaming — a ''superapp chain'' distribution play rather than a DeFi-primitives chain.", "situation": "In Jan 2025 Kaia launched Mini Dapps inside LINE (420+ apps at launch), reportedly crossing ~35M users within a month and lifting on-chain active wallets sharply — making it one of the larger EVM L1s by active-wallet count. In May 2025 Tether deployed native USDT on Kaia, and at KBW / Token2049 2025 Kaia and LINE NEXT unveiled a stablecoin super-app embedding payments, remittances and DeFi into LINE and targeting KRW/JPY-pegged and other Asian stablecoins. Despite this distribution momentum, economic depth is thin: TVL sits near $10.7M and KAIA fell to record lows around $0.05 in 2025. Note the token lineage: KAIA is a 1:1 successor to Klaytn''s KLAY, which itself peaked around $4.34 in March 2021 — so measured against the predecessor''s high, the real drawdown is far steeper than the KAIA-ticker ATH suggests.", "whats_working": "Unmatched consumer distribution — direct in-app placement inside LINE (~200M+ MAU across Japan, Taiwan, Thailand, Indonesia) and KakaoTalk (dominant in South Korea); large raw active-wallet and mini-dApp signup numbers; and a credible, differentiated stablecoin/payments thesis with real partners (Tether, KakaoPay, LINE NEXT) rather than pure speculation.", "whats_not": "On-chain value is tiny (~$10.7M TVL) and mini-dApp engagement looks wide-but-shallow (airdrop/quest-driven signups, low retention and spend). The KAIA token has collapsed to record lows, weakening incentive budgets, and the entire thesis is hostage to two corporate parents'' strategy and to unsettled Korean/Japanese stablecoin regulation.", "non_economic": "High marketing/social visibility in Asia (the Kaia Wave developer program, a Kaito ''Yapper'' leaderboard, a Kaia Summit at Token2049, KBW presence). Strong regional developer mindshare inherited from the Klaytn and Finschia communities, but limited Western developer or DeFi-native attention; the narrative is consumer/retail and payments-led rather than technical.", "outlook": "BULL: the messenger distribution moat converts a fraction of 200M+ users into recurring payment/RWA activity, a consumer-fintech niche no US L2 can copy. BASE (most likely): mini-dApp counts stay headline-friendly but shallow while Kaia settles into a regional payments/stablecoin layer. BEAR: novelty fades, KR/JP stablecoin regulation stalls the thesis, KAIA grinds lower. Top risks: token depreciation eroding incentives; regulatory dependence; reliance on two corporate parents. Watch: the stablecoin super-app''s retained paying users, TVL/stablecoin supply, KAIA versus its ~$0.05 low.", "success_factors_missing": ["deep_liquidity", "retained_active_users", "token_value_accrual", "defi_ecosystem_depth", "regulatory_clarity", "value_beyond_incentives"]}', '[{"title": "DefiLlama — Kaia chain TVL (continuous with Klaytn)", "url": "https://defillama.com/chain/Kaia"}, {"title": "Kaia, LINE NEXT unveil stablecoin super-app for Asia at KBW 2025 (crypto.news)", "url": "https://crypto.news/kaia-line-next-stablecoin-super-app-for-asia-2025/"}, {"title": "Kaia''s Mini Dapps Hit 35M Users in Weeks (Crypto Times)", "url": "https://www.cryptotimes.io/2025/03/06/kaias-mini-dapps-hit-35m-users-2m-spent-in-weeks/"}, {"title": "Kaia and LINE: scaling crypto in Asia (Blockchain Capital)", "url": "https://www.blockchaincapital.com/blog/kaia-and-line-a-perfect-match-for-scaling-crypto-in-asia"}, {"title": "KAIA Price Risks New All-Time Low (CCN)", "url": "https://www.ccn.com/analysis/crypto/kaia-price-fails-breakout-all-time-low/"}, {"title": "CoinGecko — Klaytn (KLAY) ATH $4.34, Mar 2021", "url": "https://www.coingecko.com/en/coins/klaytn"}]', datetime('now'));
INSERT OR REPLACE INTO mid_chains (chain, launched, tvl, verdict, why_stuck, outlook, profile, sources, updated_at) VALUES ('ICP', '2021-05', 11710259, 'pivoting', 'The Internet Computer raised one of crypto''s largest rounds and shipped genuinely novel tech (canister smart contracts, reverse-gas, chain-key threshold cryptography), but a catastrophic 2021 launch — from ~$700 to sub-$30 within months amid insider-unlock accusations — permanently poisoned its market credibility. Years later the ambition is huge yet the on-chain economy is minuscule (~$11.7M TVL), so DFINITY keeps re-pitching the narrative — now ''the self-writing internet'' powered by on-chain AI — rather than growing measurable usage.', 'BULL: Chain Fusion (ckBTC/ckETH, native Bitcoin/Solana integration) plus the on-chain AI stack (a ''self-writing'' app builder, on-chain inference, GPU subnets) gives ICP a defensible ''full-stack decentralized cloud + AI'' niche, and a governance-passed inflation cut removes a key overhang. BASE (most likely): ICP stays a technically impressive, well-funded outlier that ships continuously and posts big raw transaction counts, but keeps struggling to translate that into DeFi TVL, sticky developers or token value — a heads-down builder the market keeps discounting. BEAR: the AI pivot proves to be another narrative cycle without durable demand, Chain Fusion assets stay niche, and continued token weakness plus centralization concerns keep capital and builders away. Top risks: narrative outrunning real usage; ICP dilution/sell-pressure history; DFINITY/NNS centralization perception; competition from cheaper AI-crypto and L2 ecosystems. Watch: ckBTC/Chain Fusion asset supply and real DeFi TVL; whether on-chain AI produces retained apps and users; execution on the inflation-reduction plan.', '{"founded": "2016", "founders": "DFINITY Foundation (Zurich), founded 2016 by Dominic Williams (chief scientist), run as a non-profit foundation with a large in-house research/engineering team.", "raised": "~$102M round in Aug 2018 co-led by Andreessen Horowitz (a16z crypto) and Polychain Capital, part of well over $190M raised across earlier rounds — among the largest crypto raises of its era. Since then funded via the foundation treasury and ICP token.", "token_symbol": "ICP", "token_ath": 700.65, "token_ath_date": "2021-05", "token_current": 2.17, "purpose": "A ''World Computer'' — a decentralized cloud that runs full applications (frontend + backend) entirely on-chain as ''canister'' smart contracts, using a reverse-gas model (developers pay ''cycles'', users pay nothing) and chain-key threshold cryptography to integrate natively with other chains without bridges.", "situation": "In 2025-2026 DFINITY has re-centered ICP on AI: a ''Caffeine'' platform pitches a ''self-writing internet'' where users build full-stack apps from prompts, and the roadmap targets on-chain LLM inference and GPU-enabled subnets. Chain Fusion continues to expand trustless multichain assets — ckBTC and ckETH plus native Bitcoin and Solana integration via chain-key signing — as the network''s most differentiated capability. On tokenomics, a governance-passed plan aims to cut ICP''s annual inflation from ~9.7% toward the ~3-5% range, and the network reports large raw throughput. Yet DeFi remains almost non-existent for a chain of this ambition and treasury — TVL is only ~$11.7M — and the token trades near $2.17, roughly 99.7% below its May-2021 ATH of ~$700. The story is a persistent pivot from ''decentralized cloud'' toward ''decentralized AI cloud,'' still searching for demand that matches the technology.", "whats_working": "Deep, well-funded engineering that ships continuously; genuinely novel primitives (fully on-chain apps, reverse-gas, chain-key/threshold crypto); Chain Fusion (ckBTC/ckETH, native BTC & Solana) as a real bridge-less multichain capability few competitors match; large raw transaction throughput; and proactive tokenomics reform via the inflation-cut plan.", "whats_not": "Almost no DeFi/economic activity relative to its ambition and treasury (~$11.7M TVL); a permanently damaged token narrative after the 2021 collapse and insider-unlock/unregistered-security litigation; perceived centralization around DFINITY and the NNS; a habit of leading with grand narratives (World Computer → self-writing internet → on-chain AI) that outrun measurable adoption; and a heavy token-dilution history.", "non_economic": "Very high developer-content and research output (frequent DFINITY roadmap posts, technical publications, active NNS governance). A committed core community and steady canister/wallet growth, but limited crossover with mainstream DeFi and persistent market skepticism stemming from the launch history.", "outlook": "BULL: Chain Fusion plus the on-chain AI stack gives ICP a defensible full-stack decentralized-cloud + AI niche, and the inflation cut removes an overhang. BASE (most likely): technically impressive and well-funded, ships continuously and posts big raw counts, but can''t convert that into TVL, sticky devs or token value. BEAR: the AI pivot is another narrative cycle, Chain Fusion stays niche, token weakness and centralization concerns keep builders away. Top risks: narrative outrunning usage, dilution/sell pressure, DFINITY/NNS centralization, AI-crypto competition. Watch: Chain Fusion asset supply and real DeFi TVL, whether on-chain AI retains apps/users, and execution on the inflation cut.", "success_factors_missing": ["defi_ecosystem_depth", "deep_liquidity", "token_value_accrual", "demand_matching_tech", "decentralization_credibility", "market_trust"]}', '[{"title": "DefiLlama — Internet Computer (ICP) chain TVL", "url": "https://defillama.com/chain/ICP"}, {"title": "DFINITY raises $102M from a16z and Polychain (TechCrunch, 2018)", "url": "https://techcrunch.com/2018/08/29/dfinity/"}, {"title": "The rise and fall of Internet Computer (CoinJournal)", "url": "https://coinjournal.net/news/the-rise-and-fall-of-internet-computer-how-icp-imploded/"}, {"title": "Internet Computer bets big on AI (CoinDesk, Sep 2025)", "url": "https://www.coindesk.com/tech/2025/09/20/internet-computer-bets-big-on-ai-as-crypto-markets-play-catch-up"}, {"title": "The Internet Computer Roadmap 2025 Update (DFINITY)", "url": "https://medium.com/dfinity/the-internet-computer-roadmap-2025-update-d9c2fd674167"}, {"title": "DFINITY hit with unregistered-security lawsuit (Decrypt)", "url": "https://decrypt.co/76614/dfinity-hit-with-lawsuit-claiming-icp-unregistered-security"}]', datetime('now'));
INSERT OR REPLACE INTO mid_chains (chain, launched, tvl, verdict, why_stuck, outlook, profile, sources, updated_at) VALUES ('IOTA', '2016-07', 1388168, 'pivoting', 'IOTA spent eight years and its entire brand on a feeless IoT DAG (the Tangle) that never reached decentralized production, then in 2025 abandoned that thesis wholesale to relaunch as a fee-charging, Move-based Proof-of-Stake L1 built on Sui-derived tech — a full identity reset that left it competing in a crowded smart-contract field where it has no lead.', 'BULL: the Abu Dhabi ADGM DLT foundation ($100M+ in tokens over four years) plus a modern MoveVM stack lets IOTA become the compliance-and-RWA chain for the Gulf, converting real-world assets on-chain with real institutional cover. BASE (most likely): a technically capable but low-liquidity L1 (~$1.4M TVL) that keeps shipping and courting government/enterprise pilots, retaining a loyal EU/German community but never regaining relevance or price. BEAR: the pivot dilutes the one thing IOTA was known for (feeless IoT) without winning DeFi share; TVL and devs stay negligible, the token drifts near lows, and the Abu Dhabi fund becomes the main thing keeping the lights on. Top risks: post-Rebased fees undercut the machine-economy story; zero DeFi moat versus Sui/Aptos/Sei; a token ~99% below ATH signaling capital flight; reliance on a token-denominated treasury. Watch: IOTA L1/EVM TVL and active-address trend through 2026; whether any real RWA deals close via the Abu Dhabi foundation; validator decentralization post-Coordicide.', '{"founded": "2016-07", "founders": "David Sønstebø, Dominik Schiener, Sergey Ivancheglo and Serguei Popov (project initiated 2015; mainnet 2016). Sønstebø was formally parted ways with in Dec 2020 and Ivancheglo left in 2019 after founder disputes; Dominik Schiener remains chairman and the public face.", "raised": "Funded by a 2015 public crowdsale of ~1,300 BTC (~US$500,000 at the time). In 2025 the IOTA Ecosystem DLT Foundation was registered with Abu Dhabi''s ADGM and seeded with over $100M in IOTA tokens vesting over four years.", "token_symbol": "IOTA", "token_ath": 5.25, "token_ath_date": "2017-12", "token_current": 0.03719786, "purpose": "Originally a feeless, minerless DAG (''the Tangle'') for IoT/machine-to-machine micropayments and data integrity. As of the 2025 Rebased upgrade it is a general-purpose smart-contract L1 (MoveVM + EVM layer) targeting decentralized apps, staking and real-world-asset tokenization.", "situation": "On 5 May 2025 IOTA executed the ''Rebased'' migration from the old Stardust/Tangle network to a new Move-based, Delegated-Proof-of-Stake L1 using Mysticeti consensus (technology derived from Sui), finally removing the centralized Coordinator that had defined ''Coordicide'' for years. Thirteen genesis validators transferred all assets in a genesis ceremony, and the chain now offers Move L1 smart contracts, an EVM layer, staking rewards and sub-second finality. In parallel it stood up a $100M+ DLT foundation in Abu Dhabi (the first registered under ADGM''s DLT rules) to push RWA and Middle East adoption. Despite the modern stack, on-chain economics are tiny: IOTA EVM TVL sits near $1.4M, down from ~$90M highs in 2024, and the token trades ~99% below its 2017 ATH.", "whats_working": "A genuinely modern, decentralized L1 finally shipped after years of delay; credible institutional positioning via the Abu Dhabi ADGM foundation and the RWA angle; a durable, loyal European (especially German) community and long-standing enterprise/government-pilot relationships; and sub-second finality plus staking now live.", "whats_not": "The pivot discarded IOTA''s one distinctive identity (feeless IoT/Tangle) — introducing fees undercuts the machine-economy micropayment pitch. It now competes directly with Sui/Aptos/Sei on Move/DeFi where it has no liquidity, no moat and negligible developer traction (~$1.4M TVL). Tokenomics questions dogged the migration, and much of the runway is token-denominated treasury rather than external revenue.", "non_economic": "Very active foundation comms (regular blog progress reports, a 2025 review) and some academic attention (a peer-reviewed MDPI Sensors comparison of Tangle 2.0 vs Rebased). Strong legacy brand recognition and community loyalty, but social momentum is muted and much of the narrative is now foundation-driven rather than grassroots or developer-driven.", "outlook": "BULL: the ADGM Abu Dhabi foundation plus a modern MoveVM stack makes IOTA the Gulf''s compliance-and-RWA chain. BASE (most likely): capable but low-liquidity, keeps shipping and courting pilots, loyal EU community, no relevance/price recovery. BEAR: the pivot dilutes the feeless-IoT identity without winning DeFi share and the fund keeps the lights on. Top risks: fees undercut the machine-economy story, no DeFi moat, capital flight, token-denominated treasury reliance. Watch: L1/EVM TVL and active addresses, real RWA deals via Abu Dhabi, validator decentralization.", "success_factors_missing": ["product_market_fit", "defi_liquidity", "developer_ecosystem", "clear_identity", "sustainable_revenue"]}', '[{"title": "The IOTA Rebased Mainnet Upgrade (IOTA Foundation blog)", "url": "https://blog.iota.org/rebased-mainnet-upgrade/"}, {"title": "IOTA becomes first DLT Foundation registered with ADGM in Abu Dhabi", "url": "https://www.adgm.com/media/announcements/iota-becomes-the-first-dlt-foundation-registered-with-adgm-in-abu-dhabi"}, {"title": "IOTA launches $100M Abu Dhabi foundation (Cointelegraph)", "url": "https://cointelegraph.com/news/iota-launches-100-million-abu-dhabi-foundation-for-middle-east-expansion"}, {"title": "IOTA (technology) — founding, crowdsale, founder departures (Wikipedia)", "url": "https://en.wikipedia.org/wiki/IOTA_(technology)"}, {"title": "From IOTA Tangle 2.0 to Rebased: A Comparative Analysis (MDPI Sensors, 2025)", "url": "https://www.mdpi.com/1424-8220/25/11/3408"}, {"title": "IOTA EVM — DeFi TVL (DefiLlama)", "url": "https://defillama.com/chain/iota-evm"}]', datetime('now'));
INSERT OR REPLACE INTO mid_chains (chain, launched, tvl, verdict, why_stuck, outlook, profile, sources, updated_at) VALUES ('Neo', '2016-10', 1423948, 'drifting', 'The self-styled ''Chinese Ethereum'' of the 2017 cycle never rebuilt developer or capital momentum after that peak, and in late 2025 its two co-founders entered a publicly-reported dispute over treasury control and financial disclosure — with Da Hongfei reported to be stepping back from Neo mainnet as of 1 Jan 2026 — leaving the chain leaderless on its core network just when it needed direction.', 'BULL: the governance dispute forces genuine treasury transparency and multisig custody, Neo X (the EVM sidechain) plus the N3↔X message bridge attracts EVM developers, and a cleaned-up structure lets the still-sizeable treasury fund a real comeback. BASE (most likely): Neo N3 keeps running with a small loyal base and ~$1.4M TVL while attention and resources fragment across Neo X and the founder rift; the token stays a deep-discount legacy name with little new adoption. BEAR: the governance breakdown hardens into a permanent split, the promised 2026 financial report deepens distrust, developers and community exit, and Neo becomes a maintained-but-abandoned relic of the 2017 cycle. Top risks: co-founder deadlock and treasury opacity; key-man/custody concentration of NEO/GAS; leadership attention diverted from mainnet; near-total loss of the original China-market narrative post-regulation. Watch: whether the 2026 financial report actually lands and what it shows; treasury moved to multisig; Neo X TVL and bridge usage versus N3; any resolution or entrenchment of the founder split.', '{"founded": "2014", "founders": "Da Hongfei and Erik Zhang, who founded Antshares in 2014 (rebranded to Neo in 2017). Both remain involved but are, as of late 2025, in an openly reported dispute; per that reporting Da is stepping back from Neo mainnet in early 2026 to focus on Neo X and a separate project.", "raised": "Funded via 2015-2016 ICOs (two token sales) and grew a large treasury of NEO/GAS during the 2017 bull run. The current dispute centers on a Neo Foundation treasury whose primary assets are its own NEO and GAS holdings.", "token_symbol": "NEO", "token_ath": 198.38, "token_ath_date": "2018-01", "token_current": 1.91, "purpose": "A smart-contract platform for a ''smart economy'' — digitized assets, digital identity and dApps — using a dual-token model (NEO for governance/staking, GAS to pay for network usage) and dBFT consensus. Neo N3 is the current mainnet; Neo X is an EVM-compatible, MEV-resistant sidechain extending it to the Ethereum developer world.", "situation": "In late December 2025 the two co-founders entered a publicly-reported feud: per coverage in Crypto Briefing and CCN, Erik Zhang accused Da Hongfei of failing to deliver promised financial statements and of controlling foundation assets without disclosure, while Da countered that Zhang holds a super-majority of the treasury and consensus voting power in personal custody and refuses to move it to multisig. The two reportedly agreed Da would cease Neo mainnet development as of 1 Jan 2026 to focus on Neo X and a separate project, and Zhang committed to releasing a 2025 financial report in early 2026. On the product side Neo shipped Neo X (an EVM sidechain with dBFT consensus) and an N3↔X message bridge, but on-chain value is small (~$1.4M TVL) and NEO trades ~99% below its Jan-2018 ATH. (These are attributed, publicly-reported claims between named project leaders, not findings of wrongdoing.)", "whats_working": "A long operating history and a still-functional, distinct tech stack (dBFT single-block finality, the dual-token NEO/GAS model). Neo X gives it a credible EVM on-ramp with an MEV-resistance angle and a working N3↔X bridge, and there is still a meaningful (if reduced) treasury and a residual brand from the 2017 cycle.", "whats_not": "An open, public dispute among founders over money and control is the worst possible signal for a chain that already lost momentum — it paralyzes governance, concentrates custody/key-man risk, and erodes the trust needed to attract builders. The core mainnet is reportedly losing its most prominent leader, adoption and TVL are negligible, and the original ''Chinese Ethereum'' thesis was hollowed out by China''s crypto crackdown.", "non_economic": "Heavy negative social signal in late 2025 / early 2026: public accusations traded between the founders, coverage across CCN, Crypto Briefing and Chinese-market outlets, and community sentiment described as displeasure with both parties. Neo News Today and official channels still document Neo X development, but the dominant narrative is governance dysfunction rather than shipping.", "outlook": "BULL: the dispute forces treasury transparency and multisig custody, and Neo X plus the N3↔X bridge attracts EVM developers, letting the treasury fund a comeback. BASE (most likely): N3 keeps running with a small base and ~$1.4M TVL while resources fragment across Neo X and the founder rift. BEAR: the breakdown hardens into a permanent split, the financial report deepens distrust, and Neo becomes a maintained-but-abandoned relic. Top risks: co-founder deadlock and treasury opacity, key-man/custody concentration, leadership diverted from mainnet, lost China narrative. Watch: whether the 2026 financial report lands, treasury moved to multisig, Neo X TVL versus N3, resolution of the split.", "success_factors_missing": ["governance_stability", "treasury_transparency", "developer_ecosystem", "leadership_alignment", "market_narrative"]}', '[{"title": "DefiLlama — Neo chain TVL", "url": "https://defillama.com/chain/Neo"}, {"title": "Neo co-founders'' public dispute over treasury and transparency (Crypto Briefing)", "url": "https://cryptobriefing.com/neo-founders-transparency-clash/"}, {"title": "Neo co-founders trade barbs over finances and control (CCN)", "url": "https://www.ccn.com/news/crypto/neo-blockchain-controversy-co-founders-trade-barb-over-finances-and-control/"}, {"title": "Neo unveils details of EVM-compatible sidechain (Neo News Today)", "url": "https://neonewstoday.com/development/neo-unveils-details-of-evm-compatible-sidechain/"}, {"title": "Neo X — Neo''s EVM-based sidechain (official)", "url": "https://x.neo.org/"}]', datetime('now'));
